namespace sv_9c938a4814c146c4ac28307543013d4f.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@page "/apply"
@rendermode InteractiveServer
@using sv_9c938a4814c146c4ac28307543013d4f.Components.Pages.ApplySteps
@using sv_9c938a4814c146c4ac28307543013d4f.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* Step Indicator Bar *@
    <nav class="mb-4">
        <div class="d-flex justify-content-between position-relative">
            @* Connector line behind the circles *@
            <div class="position-absolute w-100" style="top: 18px; left: 0; z-index: 0;">
                <div class="mx-auto" style="height: 2px; background: #dee2e6; width: 90%; margin-left: 5%;"></div>
            </div>

            @for (int i = 0; i < StepNames.Length; i++)
            {
                var stepIndex = i;
                var isCurrent = stepIndex == CurrentStep;
                var isCompleted = stepIndex < CurrentStep;
                var isFuture = stepIndex > CurrentStep;

                <div class="text-center position-relative" style="z-index: 1; flex: 1; cursor: @(isCompleted ? "pointer" : "default");"
                     @onclick="() => GoToCompletedStep(stepIndex)">
                    <div class="rounded-circle d-inline-flex align-items-center justify-content-center mb-1"
                         style="width: 36px; height: 36px;
                                background: @(isCurrent ? "#0d6efd" : isCompleted ? "#198754" : "#dee2e6");
                                color: @(isFuture ? "#6c757d" : "white");
                                font-size: 14px; font-weight: 600;
                                transition: background 0.2s;">
                        @if (isCompleted)
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            <span>@(stepIndex + 1)</span>
                        }
                    </div>
                    <div class="small @(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")"
                         style="font-size: 0.75rem;">
                        @StepNames[stepIndex]
                    </div>
                </div>
            }
        </div>
    </nav>

    @* Validation / error banner *@
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger alert-dismissible fade show" role="alert">
            @ErrorMessage
            <button type="button" class="btn-close" @onclick="() => ErrorMessage = null"></button>
        </div>
    }

    @* Step content *@
    @switch (CurrentStep)
    {
        case 0:
            <StepPersonalInfo FullName="@FullName" Email="@Email" Phone="@Phone" Address="@Address"
                              FullNameChanged="v => FullName = v" EmailChanged="v => Email = v"
                              PhoneChanged="v => Phone = v" AddressChanged="v => Address = v"
                              OnNext="HandlePersonalInfoNext" />
            break;
        case 1:
            <StepWorkHistory Entries="@WorkEntries"
                             OnBack="GoBack" OnNext="HandleWorkHistoryNext" />
            break;
        case 2:
            <StepReferences References="@References"
                            OnBack="GoBack" OnNext="HandleReferencesNext" />
            break;
        case 3:
            <StepCoverLetter CoverLetter="@CoverLetter" CoverLetterChanged="v => CoverLetter = v"
                             MaxLength="2000"
                             OnBack="GoBack" OnNext="HandleCoverLetterNext" />
            break;
        case 4:
            <StepReviewSubmit FullName="@FullName" Email="@Email" Phone="@Phone" Address="@Address"
                              WorkEntries="@WorkEntries" References="@References"
                              CoverLetter="@CoverLetter"
                              IsSubmitting="@IsSubmitting" IsSubmitted="@IsSubmitted"
                              ApplicationId="@ApplicationId"
                              OnEdit="GoToStep" OnBack="GoBack" OnSubmit="HandleSubmit" />
            break;
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int CurrentStep { get; set; }
    private string? ErrorMessage { get; set; }

    // Step 1 state
    private string FullName { get; set; } = "";
    private string Email { get; set; } = "";
    private string Phone { get; set; } = "";
    private string Address { get; set; } = "";

    // Step 2 state
    private List<WorkEntryModel> WorkEntries { get; set; } = new() { new WorkEntryModel() };

    // Step 3 state
    private List<ReferenceModel> References { get; set; } = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 state
    private string CoverLetter { get; set; } = "";

    // Step 5 state
    private bool IsSubmitting { get; set; }
    private bool IsSubmitted { get; set; }
    private int? ApplicationId { get; set; }

    private void GoToCompletedStep(int step)
    {
        if (step < CurrentStep)
        {
            ErrorMessage = null;
            CurrentStep = step;
        }
    }

    private void GoToStep(int step)
    {
        ErrorMessage = null;
        CurrentStep = step;
    }

    private void GoBack()
    {
        ErrorMessage = null;
        if (CurrentStep > 0) CurrentStep--;
    }

    private async Task HandlePersonalInfoNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Please fill in all personal info fields.";
            return;
        }

        var emailValid = await ApplicationService.ValidateEmailAsync(Email.Trim());
        if (!emailValid)
        {
            ErrorMessage = "The email address provided is not valid.";
            return;
        }

        CurrentStep = 1;
    }

    private void HandleWorkHistoryNext()
    {
        ErrorMessage = null;
        foreach (var entry in WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                ErrorMessage = "Please fill in company, title, and start date for all work entries.";
                return;
            }
        }
        CurrentStep = 2;
    }

    private void HandleReferencesNext()
    {
        ErrorMessage = null;
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        CurrentStep = 3;
    }

    private void HandleCoverLetterNext()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "Please write a cover letter before proceeding.";
            return;
        }
        CurrentStep = 4;
    }

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            var workHistory = new WorkHistory(
                WorkEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description)).ToList());

            var refs = References.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(
                new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()),
                workHistory, refs, CoverLetter.Trim());

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }

    // Mutable view-model classes so child components can bind to fields
    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

