@using static sv_9c938a4814c146c4ac28307543013d4f.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Personal Information</h4>

        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" value="@FullName"
                   @oninput="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")"
                   placeholder="John Doe" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" value="@Email"
                   @oninput="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")"
                   placeholder="john@example.com" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" value="@Phone"
                   @oninput="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")"
                   placeholder="(555) 123-4567" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" rows="2" value="@Address"
                      @oninput="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")"
                      placeholder="123 Main St, City, State ZIP"></textarea>
        </div>

        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="OnNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";

    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public EventCallback<string> AddressChanged { get; set; }

    [Parameter] public EventCallback OnNext { get; set; }
}

@using static sv_9c938a4814c146c4ac28307543013d4f.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Work History</h4>

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            var entry = Entries[index];

            <div class="border rounded p-3 mb-3 position-relative">
                <h6 class="text-muted mb-3">Position @(index + 1)</h6>

                @if (Entries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger position-absolute" style="top: 12px; right: 12px;"
                            @onclick="() => RemoveEntry(index)">Remove</button>
                }

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Company"
                               @oninput="e => entry.Company = e.Value?.ToString() ?? """ />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Title"
                               @oninput="e => entry.Title = e.Value?.ToString() ?? """ />
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                               @onchange="e => entry.StartDate = ParseDate(e.Value)" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                               disabled="@entry.IsCurrent"
                               @onchange="e => entry.EndDate = ParseNullableDate(e.Value)" />
                    </div>
                    <div class="col-md-4 d-flex align-items-end pb-2">
                        <div class="form-check">
                            <input type="checkbox" class="form-check-input" id="current-@index"
                                   checked="@entry.IsCurrent"
                                   @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                            <label class="form-check-label" for="current-@index">Currently working here</label>
                        </div>
                    </div>
                </div>

                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" value="@entry.Description"
                              @oninput="e => entry.Description = e.Value?.ToString() ?? """></textarea>
                </div>
            </div>
        }

        <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
            <button class="btn btn-primary" @onclick="OnNext">Next &rarr;</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private static string FormatDate(DateTime date) =>
        date == default ? "" : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? "";

    private static DateTime ParseDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : default;

    private static DateTime? ParseNullableDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : null;
}

@using static sv_9c938a4814c146c4ac28307543013d4f.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">References</h4>

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            var r = References[index];

            <div class="border rounded p-3 mb-3 position-relative">
                <h6 class="text-muted mb-3">Reference @(index + 1)</h6>

                @if (References.Count > 2)
                {
                    <button class="btn btn-sm btn-outline-danger position-absolute" style="top: 12px; right: 12px;"
                            @onclick="() => RemoveReference(index)">Remove</button>
                }

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@r.Name"
                               @oninput="e => r.Name = e.Value?.ToString() ?? """ />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@r.Relationship"
                               @oninput="e => r.Relationship = e.Value?.ToString() ?? """ />
                    </div>
                </div>

                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
