@using static sv_9c938a4814c146c4ac28307543013d4f.Components.Pages.Apply

@if (IsSubmitted)
{
    <div class="card border-success">
        <div class="card-body text-center py-5">
            <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead mt-2">Your application ID is <strong>#@ApplicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    </div>
}
else
{
    <div class="card">
        <div class="card-body">
            <h4 class="card-title mb-4">Review Your Application</h4>

            @* Personal Info *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
                </div>
                <div class="bg-light rounded p-3">
                    <div class="row">
                        <div class="col-md-6 mb-1"><strong>Name:</strong> @FullName</div>
                        <div class="col-md-6 mb-1"><strong>Email:</strong> @Email</div>
                        <div class="col-md-6 mb-1"><strong>Phone:</strong> @Phone</div>
                        <div class="col-md-6 mb-1"><strong>Address:</strong> @Address</div>
                    </div>
                </div>
            </div>

            @* Work History *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
                </div>
                <div class="bg-light rounded p-3">
                    @foreach (var entry in WorkEntries)
                    {
                        <div class="mb-2 @(entry != WorkEntries.Last() ? "border-bottom pb-2" : "")">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") &ndash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1 small">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            @* References *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
                </div>
                <div class="bg-light rounded p-3">
                    @foreach (var r in References)
                    {
                        <div class="mb-2 @(r != References.Last() ? "border-bottom pb-2" : "")">
                            <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                            <small class="text-muted">@r.Email &bull; @r.Phone</small>
                        </div>
                    }
                </div>
            </div>

            @* Cover Letter *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
                </div>
                <div class="bg-light rounded p-3">
                    <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
                </div>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
                <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-2" role="status"></span>
                        <span>Submitting...</span>
                    }
                    else
                    {
                        <span>Submit Application</span>
                    }
                </button>
            </div>
        </div>
    </div>
}

