        <h4 class="card-title mb-3">Cover Letter</h4>

        <div class="mb-3">
            <textarea class="form-control" rows="10" value="@CoverLetter"
                      maxlength="@MaxLength"
                      @oninput="HandleInput"
                      placeholder="Write your cover letter here..."></textarea>
            <div class="form-text text-end">
                @((CoverLetter ?? "").Length) / @MaxLength characters
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
